#elif defined(ENA_VEC_ISA) && defined(ENA_VEC_ISA_ZVQMAC) && (NDS_VEC_RVV_VERSION >= 100)
    /* Stride in input pixels between two adjacent output pixels in x */
    const long in_ch_stride = (long)in_tensor_ch;
    const long in_row_stride = (long)in_tensor_ch * (long)in_tensor_dim_x;
    const long ker_row_stride = (long)in_tensor_ch * (long)ker_dim_x;
    /* Distance between two horizontally-adjacent input pixels for stride_x */
    const long in_x_step = (long)stride_x * in_ch_stride;

    for(long in_y = -pad_y, out_y = 0; out_y < out_tensor_dim_y; in_y += stride_y, out_y++)
    {
        long ker_y_start = MAX(0, -in_y);
        long ker_y_end_base = MIN(ker_dim_y, in_tensor_dim_y - in_y);
        long in_x = -pad_x;
        long out_x = 0;

        /* --- Process pairs of output pixels (2-pixel tiling in x) --- */
        for(; out_x + 1 < out_tensor_dim_x; out_x += 2, in_x += 2 * stride_x)
        {
            long in_x2 = in_x + stride_x;  /* input x origin for second pixel */

            /* Kernel x bounds: use the intersection so we can share weight loads */
            long ker_x_start_0 = MAX(0, -in_x);
            long ker_x_end_0   = MIN(ker_dim_x, in_tensor_dim_x - in_x);
            long ker_x_start_1 = MAX(0, -in_x2);
            long ker_x_end_1   = MIN(ker_dim_x, in_tensor_dim_x - in_x2);

            /* Shared region where both pixels have valid input */
            long ker_x_shared_start = MAX(ker_x_start_0, ker_x_start_1);
            long ker_x_shared_end   = MIN(ker_x_end_0, ker_x_end_1);

            long cur_ch = 0;
            q31_t *pBias = (q31_t*)bias;
            q7_t *out_ptr0 = out_tensor;
            q7_t *out_ptr1 = out_tensor + in_tensor_ch;

            while(cur_ch < in_tensor_ch)
            {
                long vl;
                NDS_VEC_VSETVLI(vl, in_tensor_ch - cur_ch, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
                /* Load bias into both accumulators */
                NDS_VEC_VLE32_V(NDS_VEC_V0, pBias);    /* acc for pixel 0 */
                NDS_VEC_VLE32_V(NDS_VEC_V8, pBias);    /* acc for pixel 1 */

                NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M2);

                /* Phase 1: shared kernel positions — load weight once, use for both pixels */
                if (ker_x_shared_start < ker_x_shared_end)
                {
                    const q7_t *kernel_base = ker_weight + ker_y_start * ker_row_stride + ker_x_shared_start * in_ch_stride + cur_ch;
                    const q7_t *input_base0 = in_tensor + (in_y + ker_y_start) * in_row_stride + (in_x + ker_x_shared_start) * in_ch_stride + cur_ch;
                    const q7_t *input_base1 = in_tensor + (in_y + ker_y_start) * in_row_stride + (in_x2 + ker_x_shared_start) * in_ch_stride + cur_ch;

                    for(long ker_y = ker_y_start; ker_y < ker_y_end_base; ++ker_y)
                    {
                        const q7_t *kp = kernel_base;
                        const q7_t *ip0 = input_base0;
                        const q7_t *ip1 = input_base1;

                        for(long ker_x = ker_x_shared_start; ker_x < ker_x_shared_end; ++ker_x)
                        {
                            NDS_VEC_VLE8_V(NDS_VEC_V20, kp);      /* shared weight */
                            NDS_VEC_VLE8_V(NDS_VEC_V16, ip0);     /* input pixel 0 */
                            NDS_VEC_VLE8_V(NDS_VEC_V18, ip1);     /* input pixel 1 */
                            NDS_VEC_VQMACC_VV(NDS_VEC_V0, NDS_VEC_V20, NDS_VEC_V16);
                            NDS_VEC_VQMACC_VV(NDS_VEC_V8, NDS_VEC_V20, NDS_VEC_V18);
                            kp  += in_ch_stride;
                            ip0 += in_ch_stride;
                            ip1 += in_ch_stride;
                        }

                        kernel_base += ker_row_stride;
                        input_base0 += in_row_stride;
                        input_base1 += in_row_stride;
                    }
                }

                /* Phase 2: positions only valid for pixel 0 (left edge) */
                for(long kxr = ker_x_start_0; kxr < MIN(ker_x_shared_start, ker_x_end_0); ++kxr)
                {
                    const q7_t *kp = ker_weight + ker_y_start * ker_row_stride + kxr * in_ch_stride + cur_ch;
                    const q7_t *ip = in_tensor + (in_y + ker_y_start) * in_row_stride + (in_x + kxr) * in_ch_stride + cur_ch;
                    for(long ker_y = ker_y_start; ker_y < ker_y_end_base; ++ker_y)
                    {
                        NDS_VEC_VLE8_V(NDS_VEC_V20, kp);
                        NDS_VEC_VLE8_V(NDS_VEC_V16, ip);
                        NDS_VEC_VQMACC_VV(NDS_VEC_V0, NDS_VEC_V20, NDS_VEC_V16);
                        kp += ker_row_stride;
                        ip += in_row_stride;
                    }
                }

                /* Phase 3: positions only valid for pixel 0 (right edge) */
                for(long kxr = MAX(ker_x_shared_end, ker_x_start_0); kxr < ker_x_end_0; ++kxr)
                {
                    const q7_t *kp = ker_weight + ker_y_start * ker_row_stride + kxr * in_ch_stride + cur_ch;
                    const q7_t *ip = in_tensor + (in_y + ker_y_start) * in_row_stride + (in_x + kxr) * in_ch_stride + cur_ch;
                    for(long ker_y = ker_y_start; ker_y < ker_y_end_base; ++ker_y)
                    {
                        NDS_VEC_VLE8_V(NDS_VEC_V20, kp);
                        NDS_VEC_VLE8_V(NDS_VEC_V16, ip);
                        NDS_VEC_VQMACC_VV(NDS_VEC_V0, NDS_VEC_V20, NDS_VEC_V16);
                        kp += ker_row_stride;
                        ip += in_row_stride;
                    }
                }

                /* Phase 4: positions only valid for pixel 1 (left edge) */
                for(long kxr = ker_x_start_1; kxr < MIN(ker_x_shared_start, ker_x_end_1); ++kxr)
                {
                    const q7_t *kp = ker_weight + ker_y_start * ker_row_stride + kxr * in_ch_stride + cur_ch;
                    const q7_t *ip = in_tensor + (in_y + ker_y_start) * in_row_stride + (in_x2 + kxr) * in_ch_stride + cur_ch;
                    for(long ker_y = ker_y_start; ker_y < ker_y_end_base; ++ker_y)
                    {
                        NDS_VEC_VLE8_V(NDS_VEC_V20, kp);
                        NDS_VEC_VLE8_V(NDS_VEC_V16, ip);
                        NDS_VEC_VQMACC_VV(NDS_VEC_V8, NDS_VEC_V20, NDS_VEC_V16);
                        kp += ker_row_stride;
                        ip += in_row_stride;
                    }
                }

                /* Phase 5: positions only valid for pixel 1 (right edge) */
                for(long kxr = MAX(ker_x_shared_end, ker_x_start_1); kxr < ker_x_end_1; ++kxr)
                {
                    const q7_t *kp = ker_weight + ker_y_start * ker_row_stride + kxr * in_ch_stride + cur_ch;
                    const q7_t *ip = in_tensor + (in_y + ker_y_start) * in_row_stride + (in_x2 + kxr) * in_ch_stride + cur_ch;
                    for(long ker_y = ker_y_start; ker_y < ker_y_end_base; ++ker_y)
                    {
                        NDS_VEC_VLE8_V(NDS_VEC_V20, kp);
                        NDS_VEC_VLE8_V(NDS_VEC_V16, ip);
                        NDS_VEC_VQMACC_VV(NDS_VEC_V8, NDS_VEC_V20, NDS_VEC_V16);
                        kp += ker_row_stride;
                        ip += in_row_stride;
                    }
                }

                /* Requantize and store pixel 0 */
                NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
                NDS_VEC_VSRA_VX(NDS_VEC_V0, NDS_VEC_V0, pre_rshift);
                NDS_VEC_VMUL_VX(NDS_VEC_V0, NDS_VEC_V0, out_scale);
                NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E16, NDS_VEC_VTYPE_LMUL_M4);
                NDS_VEC_VNCLIP_WX(NDS_VEC_V0, NDS_VEC_V0, post_rshift);
                NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M2);
                NDS_VEC_VNCLIP_WI(NDS_VEC_V0, NDS_VEC_V0, 0);
                NDS_VEC_VSE8_V(NDS_VEC_V0, out_ptr0);
                out_ptr0 += vl;

                /* Requantize and store pixel 1 */
                NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
                NDS_VEC_VSRA_VX(NDS_VEC_V8, NDS_VEC_V8, pre_rshift);
                NDS_VEC_VMUL_VX(NDS_VEC_V8, NDS_VEC_V8, out_scale);
                NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E16, NDS_VEC_VTYPE_LMUL_M4);
                NDS_VEC_VNCLIP_WX(NDS_VEC_V8, NDS_VEC_V8, post_rshift);
                NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M2);
                NDS_VEC_VNCLIP_WI(NDS_VEC_V8, NDS_VEC_V8, 0);
                NDS_VEC_VSE8_V(NDS_VEC_V8, out_ptr1);
                out_ptr1 += vl;

                cur_ch += vl;
                pBias += vl;
            }
            out_tensor += 2 * in_tensor_ch;
        }

        /* --- Remainder: single pixel if out_tensor_dim_x is odd --- */
        for(; out_x < out_tensor_dim_x; out_x++, in_x += stride_x)
        {
            long cur_ch = 0;
            long ker_x_start = MAX(0, -in_x);
            q31_t *pBias = (q31_t*)bias;

            while(cur_ch < in_tensor_ch)
            {
                long vl;
                NDS_VEC_VSETVLI(vl, in_tensor_ch - cur_ch, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
                NDS_VEC_VLE32_V(NDS_VEC_V0, pBias);

                const q7_t *input_ptr  = in_tensor + (in_y + ker_y_start) * in_row_stride + (in_x + ker_x_start) * in_ch_stride + cur_ch;
                const q7_t *kernel_ptr = ker_weight + ker_y_start * ker_row_stride + ker_x_start * in_ch_stride + cur_ch;

                NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M2);
                for(long ker_y = ker_y_start; ker_y < ker_y_end_base; ++ker_y)
                {
                    q7_t *input_ptr2  = (q7_t*)input_ptr;
                    q7_t *kernel_ptr2 = (q7_t*)kernel_ptr;

                    for(long ker_x = ker_x_start; ker_x < MIN(ker_dim_x, in_tensor_dim_x - in_x); ++ker_x)
                    {
                        NDS_VEC_VLE8_V(NDS_VEC_V16, input_ptr2);
                        NDS_VEC_VLE8_V(NDS_VEC_V20, kernel_ptr2);
                        NDS_VEC_VQMACC_VV(NDS_VEC_V0, NDS_VEC_V20, NDS_VEC_V16);
                        input_ptr2 += in_ch_stride;
                        kernel_ptr2 += in_ch_stride;
                    }

                    input_ptr  += in_row_stride;
                    kernel_ptr += ker_row_stride;
                }

                NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
                NDS_VEC_VSRA_VX(NDS_VEC_V0, NDS_VEC_V0, pre_rshift);
                NDS_VEC_VMUL_VX(NDS_VEC_V0, NDS_VEC_V0, out_scale);
                NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E16, NDS_VEC_VTYPE_LMUL_M4);
                NDS_VEC_VNCLIP_WX(NDS_VEC_V0, NDS_VEC_V0, post_rshift);
                NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M2);
                NDS_VEC_VNCLIP_WI(NDS_VEC_V0, NDS_VEC_V0, 0);
                NDS_VEC_VSE8_V(NDS_VEC_V0, out_tensor);
                out_tensor += vl;

                cur_ch += vl;
                pBias += vl;
            }
        }
    }

